const e=[{id:14,title:"Premium Bookstore",category:"web",description:"A modern, high-performance Ruby on Rails bookstore application. Navigate, search, and manage curated collections in an efficient workspace with stock tracking and catalog organization.",longDescription:"Premium Bookstore is a sophisticated platform built with Ruby on Rails 8, designed for seamless library management. It features a stunning, mobile-optimized UI, robust search, and a complete REST API. Security is a core focus, with Google OAuth2 and OTP verification via Devise. It includes background processing with Sidekiq and comprehensive monitoring for library health and performance.",image:"/assets/premium-bookstore.png",technologies:["Ruby on Rails 8","PostgreSQL","Tailwind CSS","Hotwire","Devise","Google OAuth2","Sidekiq","Redis"],features:["Advanced Search & Filtering","Google OAuth2 & OTP Auth","RESTful API Integration","Real-time Monitoring","Mobile-Optimized UI","Background Job Processing"],githubUrl:"https://github.com/sohamchavan07/bookstore",liveUrl:"https://bookstore.sohamchavan.site/",date:"2025"},{id:1,title:"CollegeMatch",category:"web",description:"A smart college recommendation platform that helps students find their ideal match based on academic profiles. It leverages AI to provide personalized reasoning for each recommendation, ensuring students understand why a college fits their goals.",longDescription:`CollegeMatch is an innovative AI-driven platform designed to simplify the complex process of college selection. By analyzing a student's academic achievements, extracurricular interests, and career aspirations, the platform generates a curated list of institutions that align with their profile.

The core of CollegeMatch is its integration with Groq AI, which provides transparent and personalized reasoning for every recommendation. This ensures that students don't just see a list of names, but understand exactly why a particular college is a good fit for their specific journey.

Built with Next.js and Supabase, the application offers a seamless and responsive user experience, featuring real-time data synchronization and secure student profiling.`,image:"/assets/college-portal.png",technologies:["Next.js","React","Groq AI","Supabase","Tailwind CSS"],features:["AI-Powered Personalization","Supabase Backend Integration","Interactive Student Profiling","Real-time Recommendations"],githubUrl:"https://github.com/sohamchavan07/Students-college-portal",liveUrl:"https://students-college-portal.vercel.app/",demoUrl:"https://students-college-portal.vercel.app/",date:"2026"},{id:10,title:"3D Portfolio",category:"web",description:"It's not just a portfolio, it's a playground of ideas. I'm excited to share my updated creative space, where I've put a lot of heart and late nights into showcasing projects that truly inspire me. I hope it inspires you, too.",longDescription:`This 3D Portfolio represents a leap forward in how I present my digital identity. Moving beyond static grids, I've created an immersive environment where visitors can explore my work in a more dynamic and engaging way.

The project focuses on high-performance 3D rendering in the browser, ensuring a smooth experience across devices. It serves as both a showcase for my technical capabilities in frontend development and a testament to my commitment to creative UI/UX design. The 'playground' aspect encourages exploration and interaction, making the discovery of my projects a journey rather than just a list.`,image:"/assets/car.png",technologies:["Three.js","React Three Fiber","React","Tailwind CSS"],features:["Creative Inspiration Shout-Out","Portfolio Gateway","Humor & Personality","User Management"],githubUrl:"https://github.com/sohamchavan07/portfolio3d",liveUrl:"https://portfolio.sohamchavan.site",demoUrl:"https://portfolio.sohamchavan.site",date:"2025"},{id:2,title:"Tawade Kitchen",category:"web",description:"A small snack shop website (Tawade Kitchen) showcasing products and contact information.",longDescription:`Tawade Kitchen is a clean, responsive website built for a local snack business. The goal was to create a digital presence that reflects the brand's homemade feel while providing essential information to customers.

The site features a visually appealing product catalog, integrated contact forms for inquiries, and a layout optimized for both desktop and mobile users. It demonstrates my ability to deliver functional, business-oriented web solutions with a focus on local enterprise needs.`,image:"/assets/tawade_kitchen.png",technologies:["React","Tailwind CSS","Vite"],features:["Product Catalog","Responsive Layout","Contact Form","Branding"],githubUrl:"https://github.com/sohamchavan07/tawade_kitchen.git",liveUrl:"https://tawade-kitchen.vercel.app",demoUrl:"https://tawade-kitchen.vercel.app",date:"2025",client:"Freelancer "},{id:4,title:"Shivkumar Realtors",category:"web",description:"A comprehensive real estate platform for Shivkumar Realtors, a Pune-based property firm. Features include property listings, detailed property views, service showcases, and a contact system. Built with modern web technologies for optimal performance and user experience.",longDescription:`Shivkumar Realtors is a professional-grade real estate solution developed for a prominent property firm in Pune. The platform is designed to handle high volumes of property data while maintaining a clean, intuitive interface for prospective buyers.

Key technical achievements include a performant property filtering system, high-resolution image galleries, and a robust contact management system that connects users directly with agents. The tech stack—React, TypeScript, and Tailwind CSS—was chosen for its scalability and developer efficiency, allowing for rapid deployment of new features and updates.`,image:"/assets/shivkumarrealtors.png",technologies:["React","TypeScript","Vite","Tailwind CSS","Shadcn UI","React Router","React Query"],features:["Property Listings","Detailed Property Views","Service Showcases","Contact System","Responsive Design"],githubUrl:"https://github.com/sohamchavan07/shivkumarrealtors",liveUrl:"https://shivkumarrealtors.vercel.app/",demoUrl:"https://shivkumarrealtors.vercel.app/",date:"2025",client:"Personal"},{id:5,title:"Hotel Nyala",category:"web",description:"Hotel Nyala is a conceptual hotel website created to showcase visual storytelling, clean structure, and modern web aesthetics. The site presents an imaginary luxury hotel brand, allowing you to demonstrate your creativity, design sense, and ability to build polished digital experiences.",longDescription:`Hotel Nyala is a conceptual project that explores the intersection of luxury branding and web design. The site was built to demonstrate how visual storytelling can be used to create a compelling brand narrative in a digital space.

Focusing on high-quality imagery, elegant typography, and smooth transitions, Hotel Nyala provides a premium user experience that mirrors the luxury of the imaginary hotel itself. It serves as a portfolio piece showcasing my design sensibilities and attention to detail.`,image:"/assets/hotelnyala.png",technologies:["React","Tailwind CSS","Framer Motion"],features:["Freelance","Responsive Layout","Contact Form","Branding"],githubUrl:"https://github.com/sohamchavan07/hotel-nyala",liveUrl:"https://hotel-nyala.vercel.app",demoUrl:"https://hotel-nyala.vercel.app",date:"2025",client:"Freelancer "},{id:6,title:"Rails Payment Gateway",category:"web",description:"A robust and secure payment gateway built using Ruby on Rails, designed to integrate seamless payment processing capabilities into web applications. This project demonstrates backend proficiency in Rails, API integrations, and secure transaction handling.",longDescription:`The Rails Payment Gateway is a backend-focused project designed to demonstrate the implementation of secure financial transactions in a web environment. Built with Ruby on Rails, the gateway handles complex payment flows, including authentication, transaction validation, and error handling.

This project highlights my proficiency in building modular, secure, and scalable backend architectures. It involves integrating with external payment APIs and ensuring data integrity throughout the transaction lifecycle.`,image:"/assets/payment.png",technologies:["Ruby on Rails","PostgreSQL","Stripe API"],features:["Secure Transactions","API-based Payment Flow","Modular Architecture"],githubUrl:"https://github.com/sohamchavan07/Payment-Gateway",liveUrl:"https://github.com/sohamchavan07/Payment-Gateway",demoUrl:"",date:"2025"},{id:11,title:"Sri Ram Mandir",category:"web",description:"A digital portal for Shri Ram Mandir, Shahupuri, Kolhapur. Features multilingual support (Marathi/English), event calendars, donation management, and interactive gallery, serving as a spiritual bridge for devotees.",longDescription:`The Shri Ram Mandir portal is a community-focused project designed to bridge the gap between a historical spiritual center and its modern devotees. Recognizing the diverse audience, I implemented full multilingual support (Marathi and English) to ensure accessibility for all age groups.

The application manages various temple activities, from donation tracking to event scheduling, all through a unified and secure dashboard. The interactive gallery and location integration provide a virtual window into the temple's daily life, fostering a deeper connection for devotees who cannot visit in person.`,image:"/assets/ram-mandir.jpg",technologies:["React","TypeScript","Vite","Tailwind CSS","Shadcn UI","Lucide React"],features:["Multilingual Support","Donation Management","Event Calendar","Interactive Gallery","Location Integration"],githubUrl:"https://github.com/sohamchavan07/sri-ram-mandir",liveUrl:"https://sri-ram-mandir1922.vercel.app/",demoUrl:"https://sri-ram-mandir1922.vercel.app/",date:"2026",client:"Personal"},{id:7,title:"Ferrari Case Study with DevOps",category:"web",description:"Racing Ahead with DevOps — How Ferrari accelerated innovation using Azure DevOps and real-time analytics. A visual case study showcasing branding, performance, and pipeline-driven delivery.",longDescription:`This project is a deep dive into the technical transformation of an iconic brand. It explores how Ferrari leverages DevOps practices—specifically using Azure DevOps—to accelerate their development cycles and improve the performance of their digital platforms.

The case study combines technical analysis with visual storytelling, illustrating the impact of real-time analytics and automated delivery pipelines on business agility. It serves as both a research piece and a demonstration of my ability to analyze and present complex technical transformations.`,image:"/assets/ferrari.jpeg",technologies:["Azure DevOps","Docker","Kubernetes","Grafana"],features:["Brand Case Study","Pipeline Simulations","Real-time Analytics","Technical Overview"],liveUrl:"https://ferrari-casestudy.vercel.app",githubUrl:"https://github.com/sohamchavan07/Ferrari/",demoUrl:"https://ferrari-casestudy.vercel.app/",date:"2025"},{id:8,title:"PORSCHE CASE STUDY",category:"web",description:"Porsche App Case Study — My Porsche App is a page that demonstrates the design & thinking behind a luxury automotive app for Porsche. It presents how one might optimize user experience, layout, customer interaction, and branding for a high-end app, illustrating both aesthetic and functional components. It's built likely using TypeScript & hosted on Vercel.",longDescription:`The Porsche App Case Study is a design-forward exploration of luxury app development. It focuses on the unique challenges of creating a digital experience that matches the prestige and performance of the Porsche brand.

The project delves into user experience optimization, interface design, and brand integration. By prototyping key features and interactions, I demonstrate how a high-end automotive app can enhance customer engagement and streamline vehicle management through thoughtful design and modern technology.`,image:"/assets/porsche.png",technologies:["React","TypeScript","Framer Motion","Tailwind CSS"],features:["Luxury/Brand-Focused Design","Modern Web Tech Stack","Structured Case Study","Aesthetic & Functional Components"],githubUrl:"https://github.com/sohamchavan07/porsche",liveUrl:"https://porsche-casestudy.vercel.app/",demoUrl:"https://porsche-casestudy.vercel.app/",date:"2025"},{id:9,title:"Tic-Tac-Toe Game",category:"web",description:"There are selectable difficulty levels (Easy / Medium / Hard) when playing against the computer. You can also set player names and there's a display of the score (Player 1 vs Player 2 or vs Computer). Includes a restart button to reset the board/game. The site is hosted on Vercel, suggesting a simple, clean implementation intended for fun and demonstrating interactive UI logic.",longDescription:`This Tic-Tac-Toe game is more than just a simple grid; it's a demonstration of interactive UI logic and state management. I implemented various difficulty levels for the computer opponent, ranging from random moves to more strategic play.

The game features customizable player names, persistent score tracking, and a clean, modern aesthetic. It serves as a practical example of how to build engaging, state-driven user interfaces with React, focusing on smooth transitions and a polished user experience.`,image:"/assets/tictactoe.png",technologies:["React","CSS Modules","Vite"],features:["Multiple Game Modes","Difficulty Levels","Customizable Player Names","Score Tracking"],githubUrl:"https://github.com/sohamchavan07/tic-tac-toe",liveUrl:"https://tic-tac-toe-blond-tau-89.vercel.app/",demoUrl:"https://tic-tac-toe-blond-tau-89.vercel.app/",date:"2025",client:"Personal"},{id:13,title:"Hemraj Products",category:"web",description:"An elegant e-commerce landing page for Hemraj Products, showcasing authentic handcrafted 'Karalechy Wafers' and traditional organic snacks.",longDescription:`Hemraj Products is a premium landing page developed for a local food producer specializing in traditional Indian snacks. The project focuses on bridging the gap between traditional family recipes and a modern, health-conscious audience.

The site features a clean, organic aesthetic that mirrors the quality of the products. Key technical implementations include a responsive layout optimized for mobile ordering, smooth scroll animations, and a structured product showcase that highlights the nutritional benefits of the Karale (Niger seeds). Built with React and Tailwind CSS, it offers a high-performance experience that emphasizes brand trust and product authenticity.`,image:"/assets/hemraj-products.png",technologies:["React","TypeScript","Vite","Tailwind CSS","Shadcn UI","Framer Motion"],features:["Organic Brand Identity","Mobile-First Ordering Flow","Nutritional Highlights","Responsive Product Showcase","Traditional Recipe Storytelling"],githubUrl:"https://github.com/sohamchavan07/hemraj-products",liveUrl:"https://hemraj-products.vercel.app/",date:"2025",client:"Freelancer"}];export{e as p};
